import subprocess, sys, os, base64

os.environ["WANDB_API_KEY"] = "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"
os.environ["WANDB_PROJECT"] = "autoresearch"

print("=== Installing PyTorch 2.4.1+cu118 (P100 compatible) ===")
subprocess.run([sys.executable, "-m", "pip", "install",
    "torch==2.4.1+cu118",
    "--index-url", "https://download.pytorch.org/whl/cu118",
    "-q",
], check=True)

print("\n=== Installing dependencies ===")
subprocess.run([sys.executable, "-m", "pip", "install",
    "rustbpe>=0.1.0", "tiktoken>=0.11.0", "wandb>=0.19.0",
], check=True)

print("\n=== Writing source files ===")
with open("prepare.py", "wb") as f:
    f.write(base64.b64decode(""))
with open("train.py", "wb") as f:
    f.write(base64.b64decode(""))
print("Wrote prepare.py and train.py")

print("\n=== Running prepare.py ===")
subprocess.run([sys.executable, "prepare.py", "--num-shards", "4"], check=True)

print("\n=== Running train.py ===")
result = subprocess.run([sys.executable, "train.py"], capture_output=False)
print(f"\nTrain exit code: {result.returncode}")
